prompts.prompt:
Our Node.js Express application is intermittently returning 503 errors under load. The application connects to a PostgreSQL database using the 'pg' connection pool. Here is the relevant configuration and error output:

Connection pool config:
```javascript
const pool = new Pool({
  host: process.env.DB_HOST,
  port: 5432,
  database: 'appdb',
  user: process.env.DB_USER,
  password: process.env.DB_PASSWORD,
  max: 10,
  idleTimeoutMillis: 30000,
  connectionTimeoutMillis: 2000,
});
```

The route handler:
```javascript
app.get('/api/orders', async (req, res) => {
  const client = await pool.connect();
  const userId = req.query.userId;
  const orders = await client.query(
    'SELECT o.*, oi.product_name, oi.quantity FROM orders o JOIN order_items oi ON o.id = oi.order_id WHERE o.user_id = $1 ORDER BY o.created_at DESC',
    [userId]
  );
  const enriched = await Promise.all(orders.rows.map(async (order) => {
    const shipping = await client.query('SELECT * FROM shipping_status WHERE order_id = $1', [order.id]);
    return { ...order, shipping: shipping.rows[0] };
  }));
  res.json(enriched);
});
```

Error logs during the 503 incidents:
```
2026-04-09T14:23:01.445Z ERROR: Error: timeout expired waiting for connection
    at Pool._checkTimeoutAndThrow (/app/node_modules/pg-pool/index.js:113:27)
    at Pool.connect (/app/node_modules/pg-pool/index.js:83:12)
2026-04-09T14:23:01.446Z ERROR: Error: timeout expired waiting for connection
    at Pool._checkTimeoutAndThrow (/app/node_modules/pg-pool/index.js:113:27)
2026-04-09T14:23:02.112Z WARN: Pool exhausted, 10/10 connections in use, 47 waiting
```

The application handles roughly 200 requests per second during peak hours. The 503 errors started after we added the order enrichment feature last week.

Diagnose the root cause of the connection pool exhaustion and recommend specific fixes.

Refactor the following Express.js middleware and route handler module. The code works but has grown organically and has several quality problems: mixed concerns, duplicated logic, inconsistent error handling, and poor testability. Restructure it into clean, testable components.

```javascript
const jwt = require('jsonwebtoken');
const bcrypt = require('bcrypt');
const db = require('./db');
const logger = require('./logger');
const { sendEmail } = require('./email');

const JWT_SECRET = process.env.JWT_SECRET || 'dev-secret-do-not-use';
const JWT_EXPIRY = '24h';
const BCRYPT_ROUNDS = 12;
const MAX_LOGIN_ATTEMPTS = 5;
const LOCKOUT_DURATION_MIN = 15;

function authMiddleware(req, res, next) {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) {
    return res.status(401).json({ error: 'No token provided' });
  }
  try {
    const decoded = jwt.verify(token, JWT_SECRET);
    req.user = decoded;
    next();
  } catch (err) {
    if (err.name === 'TokenExpiredError') {
      return res.status(401).json({ error: 'Token expired' });
    }
    return res.status(401).json({ error: 'Invalid token' });
  }
}

function requireRole(...roles) {
  return (req, res, next) => {
    if (!req.user) {
      return res.status(401).json({ error: 'Not authenticated' });
    }
    if (!roles.includes(req.user.role)) {
      logger.warn(`Access denied: user ${req.user.id} attempted ${req.method} ${req.path} with role ${req.user.role}`);
      return res.status(403).json({ error: 'Insufficient permissions' });
    }
    next();
  };
}

async function registerHandler(req, res) {
  const { email, password, name } = req.body;
  if (!email || !password || !name) {
    return res.status(400).json({ error: 'Email, password, and name are required' });
  }
  if (password.length < 8) {
    return res.status(400).json({ error: 'Password must be at least 8 characters' });
  }
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!emailRegex.test(email)) {
    return res.status(400).json({ error: 'Invalid email format' });
  }
  try {
    const existing = await db.query('SELECT id FROM users WHERE email = $1', [email]);
    if (existing.rows.length > 0) {
      return res.status(409).json({ error: 'Email already registered' });
    }
    const hashedPassword = await bcrypt.hash(password, BCRYPT_ROUNDS);
    const result = await db.query(
      'INSERT INTO users (email, password_hash, name, role, created_at) VALUES ($1, $2, $3, $4, NOW()) RETURNING id, email, name, role',
      [email, hashedPassword, name, 'user']
    );
    const user = result.rows[0];
    const token = jwt.sign({ id: user.id, email: user.email, role: user.role }, JWT_SECRET, { expiresIn: JWT_EXPIRY });
    try {
      await sendEmail(email, 'Welcome!', `Hi ${name}, your account has been created.`);
    } catch (emailErr) {
      logger.error('Failed to send welcome email', { userId: user.id, error: emailErr.message });
    }
    res.status(201).json({ user, token });
  } catch (err) {
    logger.error('Registration failed', { error: err.message });
    res.status(500).json({ error: 'Registration failed' });
  }
}

async function loginHandler(req, res) {
  const { email, password } = req.body;
  if (!email || !password) {
    return res.status(400).json({ error: 'Email and password are required' });
  }
  try {
    const result = await db.query(
      'SELECT id, email, password_hash, name, role, login_attempts, locked_until FROM users WHERE email = $1',
      [email]
    );
    if (result.rows.length === 0) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }
    const user = result.rows[0];
    if (user.locked_until && new Date(user.locked_until) > new Date()) {
      const remaining = Math.ceil((new Date(user.locked_until) - new Date()) / 60000);
      return res.status(423).json({ error: `Account locked. Try again in ${remaining} minutes.` });
    }
    const valid = await bcrypt.compare(password, user.password_hash);
    if (!valid) {
      const attempts = (user.login_attempts || 0) + 1;
      if (attempts >= MAX_LOGIN_ATTEMPTS) {
        const lockUntil = new Date(Date.now() + LOCKOUT_DURATION_MIN * 60000);
        await db.query('UPDATE users SET login_attempts = $1, locked_until = $2 WHERE id = $3', [attempts, lockUntil.toISOString(), user.id]);
        logger.warn(`Account locked due to ${attempts} failed login attempts`, { userId: user.id });
        await sendEmail(user.email, 'Account Locked', `Your account has been locked due to ${attempts} failed login attempts. It will be unlocked in ${LOCKOUT_DURATION_MIN} minutes.`);
        return res.status(423).json({ error: `Account locked after ${MAX_LOGIN_ATTEMPTS} failed attempts. Try again in ${LOCKOUT_DURATION_MIN} minutes.` });
      }
      await db.query('UPDATE users SET login_attempts = $1 WHERE id = $2', [attempts, user.id]);
      return res.status(401).json({ error: 'Invalid credentials' });
    }
    await db.query('UPDATE users SET login_attempts = 0, locked_until = NULL WHERE id = $1', [user.id]);
    const token = jwt.sign({ id: user.id, email: user.email, role: user.role }, JWT_SECRET, { expiresIn: JWT_EXPIRY });
    res.json({ user: { id: user.id, email: user.email, name: user.name, role: user.role }, token });
  } catch (err) {
    logger.error('Login failed', { error: err.message });
    res.status(500).json({ error: 'Login failed' });
  }
}

module.exports = { authMiddleware, requireRole, registerHandler, loginHandler };
```

Provide the refactored code with clear module boundaries, explain your structural decisions, and note any security issues you fix along the way.
